import { Component, signal, NO_ERRORS_SCHEMA } from '@angular/core';
import { CommonModule } from '@angular/common';
import { TagModule } from 'primeng/tag';
import { ButtonModule } from 'primeng/button';
import { MatDialog } from '@angular/material/dialog';
import { LeadEditDialog } from '../../components/lead-edit-dialog/lead-edit-dialog';
import { LeadService } from '../../../../core/services/leads.service';
import { ActivatedRoute } from '@angular/router';
import { LeadActivityDialog } from '../../components/lead-activity-dialog/lead-activity-dialog';
import { LeadAddressDialog } from '../../components/lead-address-dialog/lead-address-dialog';
import { EmailThreadsSection } from '../../components/email-threads/email-threads-section';
import { PhoneComponent } from '../../../../core/components/phone/phone.component';

@Component({
  selector: 'app-lead-detail',
  standalone: true,
  schemas: [NO_ERRORS_SCHEMA],
  imports: [CommonModule, TagModule, ButtonModule, EmailThreadsSection, PhoneComponent],
  templateUrl: 'lead-detail.html',
})
export class LeadDetail {


  lead_id = signal(null)
  lead:any = signal({})
  activities:any = signal([])

  constructor(public dialog:MatDialog, public leads_service: LeadService, public route:ActivatedRoute){
    this.lead_id.set(this.route.snapshot.paramMap.get('id'));
  }

  ngOnInit(){
    this.getDetail()
  }


  openEdit(){
    this.dialog.open(LeadEditDialog, {
      data: this.lead()
    }).afterClosed().subscribe(res=>{
      if(res){
        this.getDetail()
      }
    })
  }

  getDetail(){
    this.leads_service.getDetail(this.lead_id()).subscribe(res=>{
      this.lead.set(res)
    })
  }

  createActivity(){
    this.dialog.open(LeadActivityDialog,{
      data: {
        lead_id: this.lead_id()
      }
    }).afterClosed().subscribe(res=>{
      if(res){
        this.getDetail()
      }
    })
  }

  createAddress(){
    this.dialog.open(LeadAddressDialog,{
      data: {
        lead_id: this.lead_id()
      }
    }).afterClosed().subscribe(res=>{
      if(res){
        this.getDetail()
      }
    })
  }

  mapsUrl(address): string {
    const parts = [
      address.street_address,
      address.city,
      address.state,
      address.postal_code,
      address.country,
    ].filter(Boolean);

    const query = parts.join(', ');
    return `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(query)}`;
  }

}
